 1	import React, { ChangeEvent, FC, useEffect, useState } from 'react';
 2	import { XMLValidator } from 'fast-xml-parser';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  DropEvent,
 7	  FileUpload,
 8	  Text,
 9	  TextVariants,
10	  ValidatedOptions,
11	} from '@patternfly/react-core';
12	
13	export type SysprepFile = {
14	  fileName: string;
15	  isLoading: boolean;
16	  validated: ValidatedOptions;
17	  value: string;
18	};
19	
20	type SysprepFileFieldProps = {
21	  id: string;
22	  onChange: (value: string) => void;
23	  value?: string;
24	};
25	
26	const SysprepFileField: FC<SysprepFileFieldProps> = ({ id, onChange, value }) => {
27	  const { t } = useKubevirtTranslation();
28	  const [data, setData] = useState<SysprepFile>({
29	    fileName: '',
30	    isLoading: false,
31	    validated: ValidatedOptions.default,
32	    value,
33	  });
34	
35	  const onFieldChange = (newValue: string) => {
36	    setData((currentSysprepFile) => ({
37	      ...currentSysprepFile,
38	      validated:
39	        XMLValidator.validate(newValue) === true
40	          ? ValidatedOptions.default
41	          : ValidatedOptions.error,
42	      value: newValue,
43	    }));
44	  };
45	
46	  useEffect(() => {
47	    if (data.validated) {
48	      onChange(data.value);
49	    }
50	  }, [data.validated, data.value, onChange]);
51	
52	  return (
53	    <>
54	      <FileUpload
55	        onFileInputChange={(event: DropEvent, file: File) => {
56	          setData((currentData: SysprepFile) => ({ ...currentData, fileName: file.name }));
57	        }}
58	        onReadFinished={() =>
59	          setData((currentData: SysprepFile) => ({ ...currentData, isLoading: false }))
60	        }
61	        onReadStarted={() =>
62	          setData((currentData: SysprepFile) => ({ ...currentData, isLoading: true }))
63	        }
64	        onTextChange={(event: ChangeEvent<HTMLTextAreaElement>, text: string) =>
65	          onFieldChange(text)
66	        }
67	        validated={
68	          data.validated !== ValidatedOptions.error
69	            ? ValidatedOptions.default
70	            : ValidatedOptions.error
71	        }
72	        allowEditingUploadedText
73	        data-test={`sysprep-${id.toLowerCase().replace('.', '-')}-input`}
74	        filename={data.fileName}
75	        id={`sysprep-${id}-input`}
76	        isLoading={data.isLoading}
77	        isReadOnly={false}
78	        onDataChange={(event: DropEvent, text: string) => onFieldChange(text)}
79	        type="text"
80	        value={data.value}
81	      />
82	      {data.validated === ValidatedOptions.error && (
83	        <Text className="kv-sysprep--error" component={TextVariants.p}>
84	          {t('XML structure is not valid')}
85	        </Text>
86	      )}
87	    </>
88	  );
89	};
90	
91	export default SysprepFileField;

